class Solution:
    def maxTotalReward(self, rewardValues):
        vals = sorted(set(rewardValues))
        # Use Python int as bitmask: bit i set means total i is reachable
        dp = 1  # bit 0 set: total 0 reachable
        for v in vals:
            # candidates are totals x where x < v, i.e. bits 0..v-1
            mask = (1 << v) - 1
            dp |= (dp & mask) << v
        return dp.bit_length() - 1

