var maxTotalReward = function(rewardValues) {
    const vals = [...new Set(rewardValues)].sort((a, b) => a - b);
    const maxVal = vals[vals.length - 1];
    const dp = new Uint8Array(2 * maxVal + 1);
    dp[0] = 1;
    for (const v of vals) {
        for (let x = v - 1; x >= 0; x--) {
            if (dp[x]) dp[x + v] = 1;
        }
    }
    for (let i = 2 * maxVal; i >= 0; i--) {
        if (dp[i]) return i;
    }
    return 0;
};
